using Moq;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayConstructorTests
{
    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new PaymentGateway(null!));
    }
}

[TestClass]
public class ChargeAsyncTests
{
    private Mock<IPaymentProvider> _mockProvider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _mockProvider = new Mock<IPaymentProvider>();
        _gateway = new PaymentGateway(_mockProvider.Object);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccessfulCharge()
    {
        var expected = new ChargeResult("ch_123", true);
        _mockProvider.Setup(p => p.ChargeAsync("tok_valid", 50.00m))
                     .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_valid", 50.00m);

        Assert.AreEqual(expected, result);
        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderReturnsFailure_ReturnsFailedCharge()
    {
        var expected = new ChargeResult("ch_fail", false);
        _mockProvider.Setup(p => p.ChargeAsync("tok_declined", 100m))
                     .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_declined", 100m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestValidAmount_Succeeds()
    {
        _mockProvider.Setup(p => p.ChargeAsync("tok_1", 0.01m))
                     .ReturnsAsync(new ChargeResult("ch_1", true));

        var result = await _gateway.ChargeAsync("tok_1", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MaximumAllowedAmount_Succeeds()
    {
        _mockProvider.Setup(p => p.ChargeAsync("tok_max", 999_999.99m))
                     .ReturnsAsync(new ChargeResult("ch_max", true));

        var result = await _gateway.ChargeAsync("tok_max", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(null!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_1", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_1", -5m));
    }

    [TestMethod]
    public async Task ChargeAsync_ExceedsMaxAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_1", 1_000_000m));
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _mockProvider.Setup(p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
                     .ThrowsAsync(new InvalidOperationException("Provider unavailable"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_1", 25m));
    }

    [TestMethod]
    public async Task ChargeAsync_DelegatesToProviderWithCorrectArgs()
    {
        _mockProvider.Setup(p => p.ChargeAsync("tok_abc", 42.50m))
                     .ReturnsAsync(new ChargeResult("ch_x", true));

        await _gateway.ChargeAsync("tok_abc", 42.50m);

        _mockProvider.Verify(p => p.ChargeAsync("tok_abc", 42.50m), Times.Once);
    }
}

[TestClass]
public class RefundAsyncTests
{
    private Mock<IPaymentProvider> _mockProvider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _mockProvider = new Mock<IPaymentProvider>();
        _gateway = new PaymentGateway(_mockProvider.Object);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessfulRefund()
    {
        var expected = new RefundResult("re_456", true);
        _mockProvider.Setup(p => p.RefundAsync("ch_123"))
                     .ReturnsAsync(expected);

        var result = await _gateway.RefundAsync("ch_123");

        Assert.AreEqual(expected, result);
        Assert.IsTrue(result.Success);
        Assert.AreEqual("re_456", result.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ProviderReturnsFailure_ReturnsFailedRefund()
    {
        _mockProvider.Setup(p => p.RefundAsync("ch_nonexistent"))
                     .ReturnsAsync(new RefundResult("re_fail", false));

        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_WhitespaceChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync("  "));
    }

    [TestMethod]
    public async Task RefundAsync_ProviderThrows_ExceptionPropagates()
    {
        _mockProvider.Setup(p => p.RefundAsync(It.IsAny<string>()))
                     .ThrowsAsync(new InvalidOperationException("Provider down"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.RefundAsync("ch_123"));
    }

    [TestMethod]
    public async Task RefundAsync_DelegatesToProviderWithCorrectArgs()
    {
        _mockProvider.Setup(p => p.RefundAsync("ch_xyz"))
                     .ReturnsAsync(new RefundResult("re_1", true));

        await _gateway.RefundAsync("ch_xyz");

        _mockProvider.Verify(p => p.RefundAsync("ch_xyz"), Times.Once);
    }
}

[TestClass]
public class ProcessWebhookTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        var mockProvider = new Mock<IPaymentProvider>();
        _gateway = new PaymentGateway(mockProvider.Object);
    }

    [TestMethod]
    [DataRow("charge.succeeded", "Charge succeeded")]
    [DataRow("charge.failed", "Charge failed")]
    [DataRow("refund.succeeded", "Refund succeeded")]
    [DataRow("refund.failed", "Refund failed")]
    public void ProcessWebhook_KnownEventType_ReturnsHandled(string eventType, string expectedMessage)
    {
        var result = _gateway.ProcessWebhook(eventType, "{\"id\":\"evt_1\"}");

        Assert.IsTrue(result.Handled);
        Assert.AreEqual(expectedMessage, result.Message);
    }

    [TestMethod]
    public void ProcessWebhook_UnknownEventType_ReturnsNotHandled()
    {
        var result = _gateway.ProcessWebhook("invoice.created", "{\"id\":\"evt_2\"}");

        Assert.IsFalse(result.Handled);
        StringAssert.Contains(result.Message, "Unknown event type");
        StringAssert.Contains(result.Message, "invoice.created");
    }

    [TestMethod]
